//
import { TOP_ALIGN, BOTTOM_ALIGN, LEFT_ALIGN, RIGHT_ALIGN } from '../../core/align-constants';
import { NESTED_VIEW_CLASSNAME } from '../view-constants';
import { Mark } from '../../mark/mark-utils';

function NestedParser(spec) {
    let { config, bound, data = [], scale = d => d } = spec,
        x = _x(bound, scale, config.hAlign),
        y = _y(bound, scale, config.vAlign);

    let groupMark = Mark('group', `.${NESTED_VIEW_CLASSNAME}`),
        pointMark = Mark('point', null, data);

    pointMark.config = {
        ...config,
        size: {
            _type: 'encode',
            scale
        },
        x: {
            _type: 'encode',
            scale: x
        },
        y: {
            _type: 'encode',
            scale: y
        }
    };

    groupMark.children = [pointMark];
    return groupMark;
}

NestedParser.x = _x;
NestedParser.y = _y;

function _x(bound, scale, hAlign) {
    let w = bound.width;

    switch (hAlign) {
        case LEFT_ALIGN:
            return d => scale(d) / 2;
        case RIGHT_ALIGN:
            return d => w - scale(d) / 2;
        default:
            return () => w / 2;
    }
}

function _y(bound, scale, vAlign) {
    let h = bound.height;

    switch (vAlign) {
        case TOP_ALIGN:
            return d => scale(d) / 2;
        case BOTTOM_ALIGN:
            return d => h - scale(d) / 2;
        default:
            return () => h / 2;
    }
}

export { NestedParser };
